import scala.collection.mutable

def solve(n: Long, edges: Array[Array[Long]]): Long = {
    val ni = n.toInt
    val graph = Array.fill(ni)(List.empty[Array[Long]])
    for (e <- edges) {
        val u = e(0).toInt
        graph(u) = e :: graph(u)
    }

    val INF = Long.MaxValue
    val dist = Array.fill(ni)(INF)
    dist(0) = 0

    val pq = new mutable.PriorityQueue[(Long, Int)]()(Ordering.by(_._1).reverse)
    pq.enqueue((0L, 0))

    while (pq.nonEmpty) {
        val (d, u) = pq.dequeue()
        if (d <= dist(u)) {
            for (e <- graph(u)) {
                val v = e(1).toInt
                val s = e(2)
                val endTime = e(3)
                if (d <= endTime) {
                    val wait = if (d > s) d else s
                    val newTime = wait + 1
                    if (newTime < dist(v)) {
                        dist(v) = newTime
                        pq.enqueue((newTime, v))
                    }
                }
            }
        }
    }

    if (dist(ni - 1) == INF) -1 else dist(ni - 1)
}
```

