import scala.collection.mutable

def solve(n: Long, edges: Array[Array[Long]]): Long = {
    val nn = n.toInt
    if (nn == 1) return 0

    val dist = Array.fill(nn)(Long.MaxValue)
    dist(0) = 0

    val graph = Array.fill(nn)(List.empty[(Int, Long, Long)])
    for (e <- edges) {
        val u = e(0).toInt
        val v = e(1).toInt
        val s = e(2)
        val end = e(3)
        graph(u) = (v, s, end) :: graph(u)
    }

    val heap = mutable.PriorityQueue[(Long, Int)]()(Ordering.by(-_._1))
    heap.enqueue((0L, 0))

    while (heap.nonEmpty) {
        val (d, u) = heap.dequeue()
