                if (leaveTime <= end) {
                    val newTime = leaveTime + 1
                    if (newTime < dist(v)) {
                        dist(v) = newTime
                        heap.enqueue((newTime, v))
                    }
                }
            }
        }
    }

    if (dist(nn - 1) == Long.MaxValue) -1 else dist(nn - 1)
}
