import scala.collection.mutable.{PriorityQueue, ListBuffer}

object Solution {
    def solve(n: Long, edges: Array[Array[Long]]): Long = {
        val sizeN = n.toInt
        val dist = Array.fill(sizeN)(Long.MaxValue)
        dist(0) = 0

        val graph = Array.fill(sizeN)(ListBuffer[(Int, Long, Long)]())

        for (edge <- edges) {
            val u = edge(0).toInt
            val v = edge(1).toInt
            val s = edge(2)
            val e = edge(3)
            graph(u) += ((v, s, e))
        }

        implicit val ord: Ordering[(Long, Int)] = Ordering.by(-_._1)
        val pq = PriorityQueue[(Long, Int)]()(ord)
        pq.enqueue((0, 0))

        while (pq.nonEmpty) {
            val (t, u) = pq.dequeue()
            if (t == dist(u)) {
                for ((v, s, e) <- graph(u)) {
                    val leaveTime = math.max(t, s)
                    if (leaveTime <= e) {
                        val arrivalTime = leaveTime + 1
                        if (arrivalTime < dist(v)) {
                            dist(v) = arrivalTime
                            pq.enqueue((arrivalTime, v))
                        }
                    }
                }
            }
        }

        if (dist(sizeN - 1) == Long.MaxValue) -1 else dist(sizeN - 1)
    }
}
